var arrangeCoins = function(n) {
    let lo = 0n, hi = BigInt(n);
    const N = BigInt(n);
    while (lo < hi) {
        const mid = (lo + hi + 1n) / 2n;
        if (mid * (mid + 1n) / 2n <= N) lo = mid;
        else hi = mid - 1n;
    }
    return Number(lo);
};
